=== include/portal.h ===
#ifndef _PORTAL_H
#define _PORTAL_H

// ===========================================================================
//  Portais (Portal-3) — módulo dedicado.
//
//  Um portal é preso a uma superfície (parede/chão/teto) e orientado por uma
//  base ortonormal derivada da NORMAL da superfície. Como a base vem apenas da
//  normal informada, paredes diagonais (não paralelas aos eixos) funcionam sem
//  nenhum caso especial.
//
//  Portais andam SEMPRE em pares (azul + laranja). Atravessar um teleporta a
//  entidade para o par, transformando linearmente seus vetores físicos.
//
//  Este header não inclui <glad/glad.h> de propósito (ordem de include): os IDs
//  de GL são guardados como int/unsigned int, equivalentes a GLint/GLuint.
// ===========================================================================

#include <glm/vec3.hpp>
#include <glm/vec4.hpp>
#include <glm/mat4x4.hpp>

// object_id usados no fragment shader para a superfície/moldura dos portais.
// Valores altos para não colidirem com os object_id já existentes na cena.
#define PORTAL_BLUE    90
#define PORTAL_ORANGE  91

// ---------------------------------------------------------------------------
//  Portal: um portal individual.
// ---------------------------------------------------------------------------
struct Portal
{
    glm::vec3 center  = glm::vec3(0.0f);                 // centro (coords de mundo)
    glm::vec3 normal  = glm::vec3(0.0f, 0.0f, 1.0f);     // unitária, aponta p/ fora da parede
    glm::vec3 up      = glm::vec3(0.0f, 1.0f, 0.0f);     // unitária, tangente (define o "roll")
    float     width   = 1.2f;
    float     height  = 2.0f;
    int       colorId = PORTAL_BLUE;

    // Vetor "right" da base local (= up x normal).
    glm::vec3 right() const;

    // Base ortonormal rígida [ right | up | normal | center ]. É o sistema de
    // coordenadas local do portal E a model matrix usada para desenhar/estampar
    // o quad (the_plane, cuja face tem normal +z, alinha com 'normal').
    glm::mat4 frame() const;
    glm::mat4 frameInverse() const;

    // Distância com sinal de um ponto ao plano do portal (>0 = lado da normal).
    float signedDistance(const glm::vec3& p) const;

    // Fábrica: cria UM portal sobre uma parede a partir de um ponto e da normal
    // da superfície. 'upHint' é só uma dica e é reprojetada para ficar
    // perpendicular à normal; se a normal for ~vertical (chão/teto), há fallback
    // automático de eixo.
    static Portal onWall(glm::vec3 center, glm::vec3 normal,
                         glm::vec3 upHint = glm::vec3(0.0f, 1.0f, 0.0f));
};

// ---------------------------------------------------------------------------
//  Estado de travessia por entidade (de que lado de cada portal ela estava no
//  frame anterior). Mantenha UMA instância por entidade que pode atravessar.
// ---------------------------------------------------------------------------
struct PortalCrossingState
{
    float sideBlue    = 0.0f;
    float sideOrange  = 0.0f;
    bool  initialized = false;
    float bodyRadius  = 0.0f; // raio de colisão da entidade (offset frontal p/ detecção)
};

// ---------------------------------------------------------------------------
//  Contexto de GL de que o módulo precisa para renderizar. Configure UMA vez no
//  início (depois de carregar shaders e a geometria do quad).
// ---------------------------------------------------------------------------
struct PortalGLContext
{
    int    modelUniform      = -1;
    int    viewUniform       = -1;
    int    projectionUniform = -1;
    int    clipPlaneUniform  = -1;   // uniform vec4 clipPlane (vertex shader)
    int    objectIdUniform   = -1;
    int    portalPassUniform = -1;   // uniform int portalPass (fragment shader)
    void (*drawScene)()      = nullptr; // desenha toda a geometria do mundo
    void (*drawPlane)()      = nullptr; // desenha o quad "the_plane" (DrawVirtualObject)
};

void Portal_SetGLContext(const PortalGLContext& ctx);

// ---------------------------------------------------------------------------
//  PortalPair: gestor do par (azul + laranja). Núcleo matemático + travessia +
//  renderização see-through.
// ---------------------------------------------------------------------------
class PortalPair
{
public:
    Portal blue;
    Portal orange;

    PortalPair() {}

    // Cria o par já VINCULADO (link cruzado), com cores e tamanho atribuídos.
    // É a API de instanciação para o desenvolvedor — uma linha.
    static PortalPair create(Portal blue, Portal orange,
                             float width = 1.2f, float height = 2.0f);

    // --- Núcleo matemático (também usado pela física e, no futuro, pelo clone) ---
    // Matriz para TRANSFORMAÇÃO DE DIREÇÃO (velocidade, orientação): inclui o
    // giro de 180° em torno do up local — sai-se de frente para fora do destino.
    glm::mat4 transitionMatrix(const Portal& from, const Portal& to) const;
    // Matriz para TRANSFORMAÇÃO DE POSIÇÃO: sem o giro, mantém o ponto no mesmo
    // lado do plano (frente → frente) ao invés de virá-lo para trás.
    glm::mat4 positionMatrix(const Portal& from, const Portal& to) const;
    glm::vec3 transformPoint (const Portal& from, const glm::vec3& p) const; // ponto
    glm::vec3 transformVector(const Portal& from, const glm::vec3& v) const; // vetor/direção

    // --- Travessia (SNAP) ---
    // Se o centro da entidade cruzou um dos portais neste frame (dentro do
    // retângulo do portal), teleporta-a para o par, transformando posição e,
    // se fornecidos, velocity (vetor) e yaw (rotação Y / direção, em radianos).
    // Ideal para objetos (caixa, rádio). Devolve true se teleportou.
    bool teleportIfCrossed(PortalCrossingState& state,
                           glm::vec3& position,
                           glm::vec3* velocity = nullptr,
                           float* yaw = nullptr) const;

    // Variante para o JOGADOR: além de posição/velocidade, transforma a direção
    // de olhar (theta/phi, na convenção esférica do main.cpp) atravessando o
    // portal, para continuidade visual. Devolve true se teleportou.
    bool teleportPlayer(PortalCrossingState& state,
                        glm::vec3& position,
                        glm::vec3& velocity,
                        float& theta, float& phi) const;

    // --- Renderização see-through (stencil, 'depth' níveis de recursão) ---
    // stencilOffset: deslocamento nos stencil refs (pares consecutivos usam
    // 1/2, 3/4, 5/6, …).
    void renderViews(const glm::mat4& view, const glm::mat4& projection,
                     int depth = 1, int stencilOffset = 0) const;
    // Desenha as superfícies/molduras dos portais (após a cena principal).
    void renderSurfaces() const;

private:
    // O portal-par de 'p' dentro deste par.
    const Portal& other(const Portal& p) const;
    // Detecta se 'position' cruzou (frente->trás, dentro do retângulo) um dos
    // portais desde o frame anterior; atualiza o estado. Devolve o portal de
    // ENTRADA, ou nullptr se não cruzou.
    const Portal* detectCrossing(PortalCrossingState& state,
                                 const glm::vec3& position) const;
    // Reinicializa os lados guardados no estado a partir da posição atual.
    void resetSides(PortalCrossingState& state, const glm::vec3& position) const;

    // Renderiza a vista vista por UM portal (recursivo, controlado por 'depth').
    void renderOneView(const Portal& portal, const glm::mat4& view,
                       const glm::mat4& projection, int depth, int stencilRef) const;
    // Desenha o quad de um portal (para stencil ou superfície) com sua model matrix.
    void drawPortalQuad(const Portal& portal) const;
};

#endif // _PORTAL_H

=== src/portal.cpp (head) ===
// ===========================================================================
//  Portais (Portal-3) — implementação.
//
//  Estado por milestone:
//    M2 (FEITO) -> núcleo matemático (frame/transition/transform*) + fábricas.
//    M4         -> renderViews/renderSurfaces (stencil + câmera virtual + clip).
//    M5         -> teleportIfCrossed/teleportPlayer (travessia SNAP).
//
//  Usamos glm diretamente (cross/normalize/inverse/rotate) em vez de matrices.h,
//  pois aquele header define funções não-inline e incluí-lo aqui (2º translation
//  unit) causaria erro de "multiple definition" no link.
// ===========================================================================

#include "portal.h"

#include <glad/glad.h>

#include <glm/gtc/matrix_transform.hpp>
#include <glm/gtc/type_ptr.hpp>
#include <glm/geometric.hpp>

#include <cmath>

static const float PORTAL_PI = 3.14159265358979323846f;

// Contexto de GL (configurado por Portal_SetGLContext no início do programa).
static PortalGLContext g_PortalGL;

void Portal_SetGLContext(const PortalGLContext& ctx)
{
    g_PortalGL = ctx;
}

// Projeta 'p' no plano do portal e testa se cai dentro do retângulo do portal.
static bool withinRect(const Portal& portal, const glm::vec3& p)
{
    glm::vec3 d = p - portal.center;
    float x = glm::dot(d, portal.right());
    float y = glm::dot(d, portal.up);
    return std::fabs(x) <= portal.width * 0.5f
        && std::fabs(y) <= portal.height * 0.5f;
}

// ---------------------------------------------------------------------------
//  Portal — núcleo geométrico
// ---------------------------------------------------------------------------
glm::vec3 Portal::right() const
{
    return glm::normalize(glm::cross(up, normal));
}

glm::mat4 Portal::frame() const
{
    // Base ortonormal destra: r x u = n. Reortonormalizamos por segurança.
    glm::vec3 n = glm::normalize(normal);
    glm::vec3 r = glm::normalize(glm::cross(up, n));
    glm::vec3 u = glm::cross(n, r);

    // glm::mat4 recebe COLUNAS: [ right | up | normal | center ].
    return glm::mat4(
        glm::vec4(r, 0.0f),
        glm::vec4(u, 0.0f),
        glm::vec4(n, 0.0f),
        glm::vec4(center, 1.0f)
    );
}

glm::mat4 Portal::frameInverse() const
{
    // frame() é uma transformação rígida (rotação ortonormal + translação);
    // glm::inverse é exato e barato para 4x4.
    return glm::inverse(frame());
}

float Portal::signedDistance(const glm::vec3& p) const
{
    return glm::dot(p - center, normal);
}

Portal Portal::onWall(glm::vec3 center, glm::vec3 normal, glm::vec3 upHint)
{
    Portal p;
    p.center = center;

    glm::vec3 n = glm::normalize(normal);

    // Se a dica de "up" for ~paralela à normal (parede ~ chão/teto), trocamos de
    // eixo para evitar base degenerada.
    glm::vec3 h = glm::normalize(upHint);
    if (std::fabs(glm::dot(h, n)) > 0.99f)
        h = (std::fabs(n.y) > 0.99f) ? glm::vec3(0.0f, 0.0f, 1.0f)
                                     : glm::vec3(0.0f, 1.0f, 0.0f);

    glm::vec3 r = glm::normalize(glm::cross(h, n)); // right
    glm::vec3 u = glm::normalize(glm::cross(n, r)); // up reortonormalizado

    p.normal = n;
    p.up     = u;
    return p;
}

// ---------------------------------------------------------------------------
//  PortalPair — fábrica e núcleo de transformação
// ---------------------------------------------------------------------------
PortalPair PortalPair::create(Portal blue, Portal orange, float width, float height)
{
    blue.colorId   = PORTAL_BLUE;
    orange.colorId = PORTAL_ORANGE;
    blue.width   = orange.width  = width;
    blue.height  = orange.height = height;

    PortalPair pair;
    pair.blue   = blue;
    pair.orange = orange;
    return pair;
}

const Portal& PortalPair::other(const Portal& p) const
{
    return (&p == &blue) ? orange : blue;
}

glm::mat4 PortalPair::transitionMatrix(const Portal& from, const Portal& to) const
{
    // Leva o espaço local de 'from' ao de 'to', com giro de 180° em torno do
    // up local (eixo Y do frame): assim sai-se de FRENTE para fora do destino.
    // Usado para VELOCIDADE/ORIENTAÇÃO (w=0): a rotação inverte a direção de
    // entrada (apontando para o portal) para saída (apontando para fora dele).
    glm::mat4 flip = glm::rotate(glm::mat4(1.0f), PORTAL_PI, glm::vec3(0.0f, 1.0f, 0.0f));
    return to.frame() * flip * from.frameInverse();
}

glm::mat4 PortalPair::positionMatrix(const Portal& from, const Portal& to) const
{
    // Leva o espaço local de 'from' ao de 'to' SEM o giro: mantém o ponto no
    // mesmo lado do plano (frente → frente). Usado para POSIÇÃO (w=1):
    // atravessar um portal coloca a entidade na mesma posição relativa do
    // portal de destino, dentro da sala — e não atrás da parede.
    return to.frame() * from.frameInverse();
}

glm::vec3 PortalPair::transformPoint(const Portal& from, const glm::vec3& p) const
{
    glm::vec4 r = positionMatrix(from, other(from)) * glm::vec4(p, 1.0f);
    return glm::vec3(r);
}

glm::vec3 PortalPair::transformVector(const Portal& from, const glm::vec3& v) const
{
    // w = 0 -> aplica somente a parte linear (rotação), ignorando a translação.
    glm::vec4 r = transitionMatrix(from, other(from)) * glm::vec4(v, 0.0f);
    return glm::vec3(r);
}

// ---------------------------------------------------------------------------
//  Travessia (SNAP) — detecção compartilhada
// ---------------------------------------------------------------------------
// Retorna a posição da entidade deslocada para a sua "frente" (superfície frontal
// na direção da normal do portal), usada na detecção de travessia. Isso permite
// que o centro geométrico nunca cruze o plano (bloqueado pela parede), mas a
// superfície do corpo (pele/colisor) sim.
static glm::vec3 frontPosition(const Portal& p, const glm::vec3& position,
                                float bodyRadius)
{
    return position - glm::normalize(p.normal) * bodyRadius;
}

void PortalPair::resetSides(PortalCrossingState& state, const glm::vec3& position) const
{
    state.sideBlue    = blue.signedDistance(frontPosition(blue, position, state.bodyRadius));
    state.sideOrange  = orange.signedDistance(frontPosition(orange, position, state.bodyRadius));
    state.initialized = true;
}

const Portal* PortalPair::detectCrossing(PortalCrossingState& state,
                                         const glm::vec3& position) const
{
    float dB = blue.signedDistance(frontPosition(blue, position, state.bodyRadius));
    float dO = orange.signedDistance(frontPosition(orange, position, state.bodyRadius));

    const Portal* from = nullptr;
    if (state.initialized)
    {
        if (state.sideBlue > 0.0f && dB <= 0.0f && withinRect(blue, position))
            from = &blue;
        else if (state.sideOrange > 0.0f && dO <= 0.0f && withinRect(orange, position))
            from = &orange;
    }

    state.sideBlue    = dB;
    state.sideOrange  = dO;
    state.initialized = true;
    return from;
}

bool PortalPair::teleportIfCrossed(PortalCrossingState& state,
                                   glm::vec3& position,
                                   glm::vec3* velocity,
                                   float* yaw) const
{
    const Portal* from = detectCrossing(state, position);
    if (!from) return false;

    const Portal& to = other(*from);
    glm::mat4 Mp = positionMatrix(*from, to);   // posição: sem flip
    glm::mat4 Md = transitionMatrix(*from, to); // direção: com flip
    position = glm::vec3(Mp * glm::vec4(position, 1.0f));
    if (velocity)
        *velocity = glm::vec3(Md * glm::vec4(*velocity, 0.0f));
    if (yaw)
    {
        // Direção horizontal na convenção do main: (-sin(yaw), 0, -cos(yaw)).
        glm::vec3 dir(-std::sin(*yaw), 0.0f, -std::cos(*yaw));
        glm::vec3 d = glm::vec3(Md * glm::vec4(dir, 0.0f));
        *yaw = std::atan2(-d.x, -d.z);
    }
    resetSides(state, position); // evita re-trigger imediato no portal de destino
    return true;
}

bool PortalPair::teleportPlayer(PortalCrossingState& state,
                                glm::vec3& position,
                                glm::vec3& velocity,
                                float& theta, float& phi) const
{
    const Portal* from = detectCrossing(state, position);
    if (!from) return false;

    const Portal& to = other(*from);
    glm::mat4 Mp = positionMatrix(*from, to);   // posição: sem flip
    glm::mat4 Md = transitionMatrix(*from, to); // direção: com flip
    position = glm::vec3(Mp * glm::vec4(position, 1.0f));
    velocity = glm::vec3(Md * glm::vec4(velocity, 0.0f));

    // Direção de olhar (convenção esférica do main.cpp):
    //   view = (-cos(phi)sin(theta), sin(phi), -cos(phi)cos(theta))
    glm::vec3 viewDir(-std::cos(phi) * std::sin(theta),
                       std::sin(phi),
                      -std::cos(phi) * std::cos(theta));
    glm::vec3 d = glm::normalize(glm::vec3(Md * glm::vec4(viewDir, 0.0f)));

    phi = std::asin(glm::clamp(d.y, -1.0f, 1.0f));
    float cphi = std::cos(phi);
    if (std::fabs(cphi) > 1e-4f)
        theta = std::atan2(-d.x / cphi, -d.z / cphi);

    resetSides(state, position);
    return true;
}

