371	void PortalPair::renderViews(const glm::mat4& view, const glm::mat4& projection,
372	                             int depth, int stencilOffset) const
373	{
374	    if (!g_PortalGL.drawScene || !g_PortalGL.drawPlane) return;
375	
376	    // Refs de stencil distintas por portal (+ stencilOffset) evitam
377	    // interferência entre pares de portais (par 1 → 1/2, par 2 → 3/4, …).
378	    renderOneView(blue,   view, projection, depth, 1 + stencilOffset);
379	    renderOneView(orange, view, projection, depth, 2 + stencilOffset);
380	
381	    // Estado limpo para a cena/HUD que vem depois.
382	    glDisable(GL_STENCIL_TEST);
383	    glStencilMask(0xFF);
384	    glDepthMask(GL_TRUE);
385	    glDepthFunc(GL_LESS);
386	    glDepthRange(0.0f, 1.0f);
387	    glColorMask(GL_TRUE, GL_TRUE, GL_TRUE, GL_TRUE);
388	}
389	
390	void PortalPair::renderSurfaces() const
391	{
392	    // Desenha os quads dos portais com cor emissiva azul/laranja. O fragment
393	    // shader aplica a máscara elíptica (discard) + emissive_color.
394	    //
395	    // Usamos GL_LEQUAL: o depth buffer tem as profundidades da cena real
396	    // (DrawScene). Assim, objetos reais em frente ao portal ocultam a
397	    // moldura — o portal só fica visível onde não há obstrução.
398	    glDepthFunc(GL_LEQUAL);
399	    glUniform1i(g_PortalGL.portalPassUniform, 1); // moldura: descarta dentro da elipse
400	    drawPortalQuad(blue);
401	    drawPortalQuad(orange);
402	    glUniform1i(g_PortalGL.portalPassUniform, 0); // restaura
403	
404	    glDepthFunc(GL_LESS);
405	}
