337	void PortalPair::renderOneView(const Portal& portal, const glm::mat4& view,
338	                               const glm::mat4& projection, int depth, int level) const
339	{
340	    // Renderização recursiva (hall of mirrors DENTRO do par): olhando por
341	    // 'portal' vê-se a sala do par dele e, nela, o próprio 'portal' de novo —
342	    // repetindo a vista 'depth' níveis. A recursão é uma CADEIA (segue sempre o
343	    // mesmo portal), então cada nível aplica de novo a MESMA transitionMatrix:
344	    // a câmera do nível k é M^k * câmera_real.
345	    //
346	    // Aninhamento via stencil auto-limpante (algoritmo canônico):
347	    //   • descendo, INCR marca a janela aninhada (stencil: level-1 -> level);
348	    //   • subindo, DECR a desfaz (level -> level-1).
349	    // Ao retornar do topo o stencil volta a 0 — sem interferência entre portais
350	    // nem entre os pares, dispensando deslocamentos de ref por par.
351	    (void)projection; // a projeção (FOV) não muda entre níveis; só a 'view'.
352	    if (depth <= 0) return;
353	    const Portal& dest = other(portal);
354	
355	    // ---- 1) Marca a janela aninhada (INCR onde o pai já está marcado) ----
356	    // O nível 1 parte do fundo (stencil 0); os profundos, da janela do nível
357	    // anterior. LEQUAL: a parede do portal (DrawScene) está à mesma profundidade
358	    // do quad — LESS falharia — e a oclusão por geometria mais próxima é
359	    // preservada. O quad usa a 'view' DESTE nível (onde o portal reaparece).
360	    stampStencil(portal, view, level - 1, GL_INCR, GL_LEQUAL);
361	
362	    // ---- 2) Limpa a profundidade dentro da janela (stencil == level) ----
363	    // Empurra o depth para o "far" (1.0) na elipse, para a vista virtual poder
364	    // desenhar em qualquer profundidade.
365	    glStencilFunc(GL_EQUAL, level, 0xFF);
366	    glStencilOp(GL_KEEP, GL_KEEP, GL_KEEP);
367	    glDepthMask(GL_TRUE);
368	    glDepthFunc(GL_ALWAYS);
369	    glDepthRange(1.0f, 1.0f);
370	    drawPortalQuad(portal);
371	    glDepthRange(0.0f, 1.0f);
372	    glDepthFunc(GL_LESS);
373	
374	    // ---- 3) Câmera virtual deste nível ----
375	    // M (com giro de 180° no eixo Y local) coloca a câmera no lado oposto do
376	    // destino, olhando através dele, e espelha o movimento da câmera real (a
377	    // parte linear de dest_R * flipY * source_R⁻¹ é a identidade).
378	    glm::mat4 M = transitionMatrix(portal, dest);
379	    glm::mat4 virtualView = virtualViewThrough(M, view);
380	
381	    // ---- 4) Renderiza a CENA deste nível, recortada na janela ----
382	    // Plano de recorte (mundo): mantém só o lado da sala do portal de destino,
383	    // descartando o que está atrás dele. É o MESMO plano em todos os níveis,
384	    // pois sempre renderizamos o mundo real a partir de uma câmera deslocada.
385	    glm::vec3 n = glm::normalize(dest.normal);
386	    glm::vec4 clipPlane(n, -glm::dot(dest.center, n) - 0.001f);
387	
388	    glUniformMatrix4fv(g_PortalGL.viewUniform, 1, GL_FALSE, glm::value_ptr(virtualView));
389	    glUniform4fv(g_PortalGL.clipPlaneUniform, 1, glm::value_ptr(clipPlane));
390	    glEnable(GL_CLIP_DISTANCE0);
391	
392	    glColorMask(GL_TRUE, GL_TRUE, GL_TRUE, GL_TRUE);
393	    glDepthMask(GL_TRUE);
394	    glDepthFunc(GL_LESS);
395	    glStencilFunc(GL_EQUAL, level, 0xFF);   // só dentro da janela deste nível
396	    glStencilOp(GL_KEEP, GL_KEEP, GL_KEEP);
397	
398	    if (g_PortalGL.drawScene) g_PortalGL.drawScene();
399	
400	    glDisable(GL_CLIP_DISTANCE0);
401	    glm::vec4 noClip(0.0f);
402	    glUniform4fv(g_PortalGL.clipPlaneUniform, 1, glm::value_ptr(noClip));
403	
404	    // ---- 4b) Molduras (bordas azul/laranja) DESTE nível ----
405	    // O DrawScene não desenha as superfícies dos portais, então sem isto os
406	    // níveis aninhados ficariam sem borda. Ficam confinadas à janela
407	    // (stencil == level, ainda ativo) e usam a virtualView do passo 4; o anel
408	    // fica FORA da elipse, sobrevivendo ao recorte que o passo 5 fará nela.
409	    drawFramePair();
410	
411	    // ---- 5) Recursão: desce um nível pela câmera virtual ----
412	    // O portal reaparece DENTRO da cena recém-desenhada; a chamada filha esculpe
413	    // a próxima janela aninhada e sobrescreve só essa região. O nível mais raso
414	    // continua íntegro fora dela.
415	    if (depth > 1)
416	        renderOneView(portal, virtualView, projection, depth - 1, level + 1);
417	
418	    // ---- 6) Desfaz a marca deste nível (DECR: level -> level-1) ----
419	    // GL_ALWAYS: mexe SÓ no stencil, na mesma região do passo 1, sem tocar a cor
420	    // (vista já desenhada) nem a profundidade.
421	    stampStencil(portal, view, level, GL_DECR, GL_ALWAYS);
422	
423	    // Restaura o estado padrão de cor/profundidade para o resto do laço.
424	    glColorMask(GL_TRUE, GL_TRUE, GL_TRUE, GL_TRUE);
425	    glDepthMask(GL_TRUE);
426	    glDepthFunc(GL_LESS);
427	}
