254	
255	// Model matrix que posiciona o quad "the_plane" (plano XZ unitário, normal +Y)
256	// sobre o portal: mapeia o eixo local X->right, Y->normal, Z->up; escala para
257	// (width x height) e desloca 'pushOut' ao longo da normal (evita z-fighting com
258	// a parede atrás).
259	static glm::mat4 portalQuadModel(const Portal& p, float pushOut)
260	{
261	    glm::vec3 r = p.right();
262	    glm::vec3 n = glm::normalize(p.normal);
263	    glm::vec3 u = glm::normalize(p.up);
264	    glm::vec3 c = p.center + n * pushOut;
265	
266	    glm::mat4 basis(
267	        glm::vec4(r, 0.0f),   // local X -> right
268	        glm::vec4(n, 0.0f),   // local Y -> normal (the_plane aponta em +Y)
269	        glm::vec4(u, 0.0f),   // local Z -> up
270	        glm::vec4(c, 1.0f)
271	    );
272	    return basis * glm::scale(glm::mat4(1.0f),
273	                              glm::vec3(p.width * 0.5f, 1.0f, p.height * 0.5f));
274	}
