309	void PortalPair::stampStencil(const Portal& portal, const glm::mat4& view,
310	                              int compareRef, unsigned int stencilOp,
311	                              unsigned int depthFunc) const
312	{
313	    glEnable(GL_STENCIL_TEST);
314	    glStencilMask(0xFF);
315	    glColorMask(GL_FALSE, GL_FALSE, GL_FALSE, GL_FALSE); // só o stencil; sem cor
316	    glDepthMask(GL_FALSE);                               // nem profundidade
317	    glDepthFunc(depthFunc);
318	    glStencilFunc(GL_EQUAL, compareRef, 0xFF);
319	    glStencilOp(GL_KEEP, GL_KEEP, stencilOp);
320	    glUniform1i(g_PortalGL.portalPassUniform, 0); // stencil: mantém dentro da elipse
321	    glUniformMatrix4fv(g_PortalGL.viewUniform, 1, GL_FALSE, glm::value_ptr(view));
322	    drawPortalQuad(portal);
323	}
324	
325	void PortalPair::drawFramePair() const
326	{
327	    // portalPass=1 descarta o interior da elipse, deixando só o anel (a borda).
328	    // GL_LEQUAL respeita a oclusão pela cena já desenhada no depth buffer.
329	    glUniform1i(g_PortalGL.portalPassUniform, 1);
330	    glDepthFunc(GL_LEQUAL);
331	    drawPortalQuad(blue);
332	    drawPortalQuad(orange);
333	    glUniform1i(g_PortalGL.portalPassUniform, 0);
334	    glDepthFunc(GL_LESS);
335	}
